// Hand-written queries (NOT generated by sqlc).
//
// sqlc is not available in this environment, so the dispatch-preview queue
// depth query lives here, written to match the generated code style: a const
// SQL string and a method on *Queries using the DBTX interface.

package db

import (
	"context"

	"github.com/jackc/pgx/v5/pgtype"
)

const countAgentQueueDepth = `-- name: CountAgentQueueDepth :one
SELECT
  count(*) FILTER (WHERE status = 'queued') AS queued,
  count(*) FILTER (WHERE status IN ('dispatched', 'running')) AS running
FROM agent_task_queue
WHERE agent_id = $1
`

// CountAgentQueueDepthRow holds the per-agent queue depth used by the
// dispatch preview: how many tasks are waiting (queued) and how many occupy
// a concurrency slot. The running count mirrors CountRunningTasks
// ('dispatched' + 'running'), which is the set the claim path compares
// against max_concurrent_tasks.
type CountAgentQueueDepthRow struct {
	Queued  int64 `json:"queued"`
	Running int64 `json:"running"`
}

// CountAgentQueueDepth returns the queued and active (dispatched+running)
// task counts for one agent in a single scan of agent_task_queue.
func (q *Queries) CountAgentQueueDepth(ctx context.Context, agentID pgtype.UUID) (CountAgentQueueDepthRow, error) {
	row := q.db.QueryRow(ctx, countAgentQueueDepth, agentID)
	var i CountAgentQueueDepthRow
	err := row.Scan(&i.Queued, &i.Running)
	return i, err
}
